  {/* 対応AIモデル */}
  <div className="flex items-center gap-2 mt-2 text-muted-foreground">
    <span className="font-space-mono text-xs">対応:</span>
    {["Claude", "GPT-4o", "Gemini", "Llama"].map((m) => (
      <span
        key={m}
        className="font-space-mono text-xs px-2 py-0.5 border border-border text-muted-foreground"
      >
        {m}
      </span>
    ))}
  </div>
</div>

import { LandingDivider } from "@/app/_components/ui/landing-divider";
import { JukuBoxLogo } from "@/app/_components/jukubox-logo";

const links = [
  { label: "機能", href: "#機能" },
  { label: "使い方", href: "#使い方" },
  { label: "学習記録", href: "#学習記録" },
  { label: "ドキュメント", href: "#" },
  { label: "プライバシー", href: "#" },
  { label: "利用規約", href: "#" },
];

export function Footer() {
  return (
    <footer className="relative py-16 px-8 bg-background border-t border-[oklch(0.75_0.12_77/0.1)]">
      <div className="max-w-7xl mx-auto flex flex-col items-center gap-10">
        {/* ロゴ */}
        <div className="flex flex-col items-center gap-2">
          <JukuBoxLogo size="lg" />
          <p className="font-noto-serif-jp text-xs text-center text-muted-foreground">
            AI エージェントと好きなことを好きなだけ学ぶ
          </p>
        </div>

        {/* リンク */}
        <nav className="flex flex-wrap justify-center gap-x-8 gap-y-3">
          {links.map((link) => (
            <a
              key={link.label}
              href={link.href}
              className="text-xs transition-colors duration-200 text-subtle-foreground"
            >
              {link.label}
            </a>
          ))}
        </nav>

        {/* セパレーター */}
        <LandingDivider />

        {/* コピーライト */}
        <div className="flex flex-col sm:flex-row items-center gap-4">
          <p className="font-space-mono text-xs text-subtle-foreground">
            © 2025 JukuBox.ai — All rights reserved.
          </p>
          <div className="flex items-center gap-2">
            {["Claude", "GPT-4o", "Gemini"].map((model) => (
              <span
                key={model}
                className="font-space-mono text-[10px] px-2 py-0.5 border border-[oklch(0.75_0.12_77/0.12)] text-subtle-foreground"
              >
                {model}
              </span>
            ))}
          </div>
        </div>
      </div>
    </footer>
  );
}

import { LandingDivider } from "@/app/_components/ui/landing-divider";

const steps = [
  {
    number: "01",
    title: "AIエージェントを接続",
    description:
      "Claude、GPT-4o など、自分が使っているAIをそのまま接続。MCP や Skill 経由で簡単に連携できます。",
  },
  {
    number: "02",
    title: "コースを選ぶ or 作る",
    description:
      "ライブラリから既存コースを選ぶか、独自のカリキュラムを作成。社内研修にも個人学習にも対応。",
  },
  {
    number: "03",
    title: "AIと学習スタート",
    description:
      "AIエージェントがコースに沿って出題・解説・フィードバック。まるで専属の家庭教師がいるような感覚。",
  },
  {
    number: "04",
    title: "記録を確認・振り返る",
    description:
      "学習ログ・正誤記録・進捗グラフで成長を可視化。何が得意で何が苦手かが一目でわかります。",
  },
];

export function HowItWorks() {
  return (
    <section
      id="使い方"
      className="relative py-28 px-8 bg-background"
    >
      <div className="max-w-7xl mx-auto">
        {/* ヘッダー */}
        <div className="flex flex-col items-center gap-5 mb-20 text-center">
          <div className="flex items-center gap-3">
            <div className="w-8 h-px bg-primary-dim" />
            <span
              className="font-space-mono text-xs uppercase tracking-[0.25em] text-muted-foreground"
            >
              How It Works
            </span>
            <div className="w-8 h-px bg-primary-dim" />
          </div>
          <h2
            className="font-noto-serif-jp font-black text-4xl lg:text-5xl text-foreground"
          >
            使い方は、シンプル。
          </h2>
          <LandingDivider className="max-w-xs mt-2" />
        </div>

        {/* ステップ */}
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-0 relative">
          {/* コネクターライン（デスクトップ） */}
          <div
            className="hidden lg:block absolute top-10 left-[12.5%] right-[12.5%] h-px bg-[linear-gradient(90deg,transparent,var(--primary-dim)_20%,var(--primary-dim)_80%,transparent)] opacity-40"
          />

          {steps.map((step, idx) => (
            <div
              key={step.number}
              className="relative flex flex-col items-center text-center px-6 py-8 gap-5"
            >
              {/* ステップ番号 */}
              <div
                className="relative z-10 w-20 h-20 rounded-full flex items-center justify-center flex-shrink-0 bg-background-warm border border-primary-dim"
              >
                <span
                  className="font-orbitron font-black text-2xl text-primary"
                >
                  {step.number}
                </span>
              </div>

              {/* タイトル */}
              <h3
                className="font-noto-serif-jp font-bold text-base leading-snug text-foreground"
              >
                {step.title}
              </h3>

              {/* 説明 */}
              <p
                className="text-sm leading-relaxed text-muted-foreground"
              >
                {step.description}
              </p>

              {/* モバイル矢印 */}
              {idx < steps.length - 1 && (
                <div
                  className="lg:hidden text-lg mt-1 text-primary-dim"
                >
                  ↓
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

